    "sections": {
      "whenApplies": [
        "A tower crane, mobile crane, boom truck, material hoist, personnel hoist, or other hoisting equipment will move a load.",
        "Workers are rigging, signalling, receiving, landing, unhooking, or working near a suspended load.",
        "A load path crosses trades, public areas, hoarding, traffic, [[scaffolds|scaffolds]], or occupied work zones.",
        "The crane is near overhead power lines or energized equipment.",
        "A pick may be affected by wind, blind spots, radios, multiple signal persons, or limited landing area.",
        "The lift is unusual, heavy, critical, awkward, tandem, or outside routine site practice.",
        "A crane or hoist certificate, inspection, operator qualification, or communication method needs confirmation."
      ],
      "legalRequirements": [
        "Use cranes and hoists that meet the applicable standards and requirements for the equipment. {{cite:ohsr-14-2}}",
        "Confirm required certification for cranes and hoists before use. {{cite:ohsr-14-16}}",
        "Provide safe access and egress for crane and hoist equipment where required. {{cite:ohsr-14-17}}",
        "Use qualified riggers for rigging work covered by Part 15. {{cite:ohsr-15-2}}",
        "Use standard or agreed hand signals and communication methods for crane operations. {{cite:ohsr-15-20}}",
        "Inspect slings and rigging before use. {{cite:ohsr-15-31}}",
        "Control minimum distances and authorization requirements near high-voltage conductors. {{cite:ohsr-19-24-1}}",
        "Keep the required crane instructions and records current, use qualified or certified operators where required, and apply tandem-lift or critical-lift requirements when those lift types are planned. {{cite:ohsr-14-12}} {{cite:ohsr-14-14}} {{cite:ohsr-14-34}} {{cite:ohsr-14-34-1}} {{cite:ohsr-14-42}} {{cite:ohsr-14-42-1}}"
      ],
      "bestPractice": [
        "Plan exclusion zones before the load is rigged, not while the load is already in the air.",
        "Use one clearly identified signal person unless the lift plan defines a transfer of control.",
        "Keep workers out from under suspended loads and away from pinch points at landing areas.",
        "Confirm load weight from a reliable source and include rigging weight where needed.",
        "Check wind, visibility, radio function, swing radius, ground conditions, and delivery routes.",
        "Use tag lines only when they reduce risk and do not pull workers into the load path.",
        "Pause the lift when any person loses sight, communication, or control of the load."
      ],
      "requiredDocuments": [
        "Lift plan: records the site-specific control expected before the task starts. {{cite:ohsr-14-2}}",
        "Crane certification record: supports worker instruction, supervisor review, and follow-up when conditions change. {{cite:ohsr-14-16}}",
        "Operator qualification record: keeps the field method tied to the hazard, equipment, and work location. {{cite:ohsr-14-17}}",
        "Rigging inspection record: helps the [[prime-contractor-duties|prime contractor]] and affected trades coordinate overlapping work. {{cite:ohsr-15-2}}",
        "Communication plan: creates a review trail if an inspection, incident, or refusal raises the issue. {{cite:ohsr-15-20}}",
        "Equipment inspection record: confirms the plan, equipment, or instruction workers are expected to use. {{cite:ohsr-15-31}}"
      ],
      "procedure": [
        "Define the load, weight, rigging method, radius, pick point, landing point, and load path.",
        "Confirm the crane or hoist certification, inspection, capacity, setup, and operator requirements.",
        "Identify overhead power lines, public areas, traffic, hoarding, scaffolds, and adjacent trades.",
        "Assign the rigger, signal person, operator, spotters, and landing crew.",
        "Inspect slings, hardware, hooks, latches, shackles, tags, and lifting points. {{cite:ohsr-15-31}}",
        "Set the exclusion zone and communicate it to affected workers.",
        "Test communication and signals before lifting.",
        "Lift slowly enough to check balance, rigging, clearance, and worker position.",
        "Stop if wind, visibility, communication, load control, power-line clearance, or public exposure changes.",
        "Record deficiencies, inspection issues, and lift-plan changes."
      ],
      "workerChecklist": [
        "I know whether I am part of the lift crew or must stay out of the exclusion zone.",
        "I will not stand under a suspended load.",
        "I know who the signal person is.",
        "I will not touch rigging unless assigned and competent for that task.",
        "I will stay clear of pinch points when landing or unhooking loads.",
        "I know the power-line or energized-equipment restriction for this lift.",
        "I will report damaged rigging or missing tags.",
        "I will stop if communication is unclear.",
        "I will not enter the swing radius or load path without authorization.",
        "I know where to stand during the pick and landing."
      ],
      "supervisorChecklist": [
        "The lift has a plan that matches load, radius, crane, rigging, route, landing, and weather.",
        "Crane or hoist certification and inspection requirements are confirmed. {{cite:ohsr-14-16}}",
        "Riggers and signal persons are qualified for assigned duties. {{cite:ohsr-15-2}}",
        "Rigging is inspected before use. {{cite:ohsr-15-31}}",
        "Exclusion zones and communication methods are in place.",
        "Power-line distances and authorization requirements are addressed. {{cite:ohsr-19-24-1}}",
        "Affected trades and public routes are controlled.",
        "Wind, visibility, ground/support conditions, and load path are monitored.",
        "Deficiencies stop the lift until corrected."
      ],
      "commonMistakes": [
        "Starting a pick before exclusion zones are set.",
        "Using multiple signal persons without a clear handoff.",
        "Guessing load weight or ignoring rigging weight.",
        "Letting workers walk through the load path because the lift feels routine.",
        "Using damaged or untagged slings.",
        "Ignoring wind or blind spots during tower crane picks.",
        "Landing loads where workers have no escape route.",
        "Planning power-line clearance after the crane is already set up."
      ]
    },
